import logging

import cv2
import geosat.image.image_processing as ip
import matplotlib.pyplot as plt
import numpy as np
from geosat.cloud import rasterization

logger = logging.getLogger(__name__)


def show_image(image, title):
    plt.imshow(image)
    plt.title(title)
    plt.show()


def compute_smooth_ground_image(
    image, max_diff=0.15, high_pass_radius=3, denoising_radius=6, show=False
):
    s = 2 * denoising_radius + 1
    mask = np.isnan(image)
    image[mask] = -np.inf
    if show:
        show_image(image, "Raw")
    image = ip.extend_border(image, denoising_radius)
    if show:
        show_image(image, "Holes filled")
    high_pass_kernel = ip.generate_high_pass_kernel(high_pass_radius)
    image = np.abs(cv2.filter2D(image, cv2.CV_64F, high_pass_kernel))
    if show:
        show_image(image, "High pass filter")
    image = cv2.threshold(image, max_diff, 255, cv2.THRESH_BINARY_INV)[1].astype(
        np.uint8
    )
    if show:
        show_image(image, "Thresholding")
    image = cv2.medianBlur(image, s)
    if show:
        show_image(image, "Median filter")
    image[mask] = 0
    return image


def find_smooth_ground(
    cloud,
    input_code,
    output_code,
    gsd=0.05,
    max_diff=0.15,
    high_pass_radius=3,
    denoising_radius=6,
    area_threshold=10.0,
):
    if input_code == output_code:
        logger.warning(
            "Ground code and smooth ground code are equal. Value: {}".format(input_code)
        )
    image = rasterization.min_normalized_elevation_raster(
        cloud, gsd, mask=cloud.classification == input_code
    )
    image = compute_smooth_ground_image(
        image, max_diff, high_pass_radius, denoising_radius
    )
    _, labels, stats, _ = cv2.connectedComponentsWithStats(image)
    classification_image = np.empty(image.shape, dtype=cloud.classification.dtype)
    classification_image.fill(input_code)
    min_area = area_threshold / gsd**2
    for label, stat in enumerate(stats[1:], start=1):
        if stat[cv2.CC_STAT_AREA] > min_area:
            classification_image[np.where(labels == label)] = output_code

    rasterization.apply_classification_image(
        cloud, classification_image, gsd, mask=cloud.classification == input_code
    )
    logger.debug(
        "{} points classified as smooth ground".format(
            np.sum(cloud.classification == output_code)
        )
    )
